{
  "name": "FoodConnect Volunteer Portal",
  "description": "A premium volunteer portal for food rescue, featuring a silver-themed map, interactive bottom sheet, and sleek mobile UI/UX."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Donation {
  id: string;
  hotelName: string;
  distance: string;
  foodItem: string;
  quantity: number; // in kg
  expiryTime: string;
  lat: number;
  lng: number;
  imageUrl: string;
  tags: string[];
}

export interface VolunteerMapProps {
  donations: Donation[];
  selectedId: string | null;
  onSelectMarker: (id: string) => void;
}

export interface DonationSheetProps {
  donations: Donation[];
  selectedId: string | null;
  onCloseDetail: () => void;
  onSelectDonation: (id: string) => void;
}

import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, useMap } from 'react-leaflet';
import L from 'leaflet';
import { VolunteerMapProps } from '../types';

// Fix for default Leaflet marker icons in some bundlers
const iconUrl = 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png';
const shadowUrl = 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png';

// Custom emerald pin icon
const emeraldIcon = new L.Icon({
  iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-green.png',
  shadowUrl: shadowUrl,
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowSize: [41, 41]
});

// Component to handle map centering logic
const MapController: React.FC<{ selectedLat: number | null; selectedLng: number | null }> = ({ selectedLat, selectedLng }) => {
  const map = useMap();

  useEffect(() => {
    if (selectedLat !== null && selectedLng !== null) {
      map.flyTo([selectedLat, selectedLng], 15, {
        animate: true,
        duration: 1.5,
      });
    }
  }, [selectedLat, selectedLng, map]);

  return null;
};

const VolunteerMap: React.FC<VolunteerMapProps> = ({ donations, selectedId, onSelectMarker }) => {
  const [isMounted, setIsMounted] = useState(false);

  // Next.js/SSR "window is not defined" fix: only render map on client mount
  useEffect(() => {
    setIsMounted(true);
  }, []);

  if (!isMounted) {
    return (
      <div className="w-full h-full bg-slate-200 flex items-center justify-center animate-pulse">
        <span className="text-slate-400 font-medium tracking-wide">Loading Map...</span>
      </div>
    );
  }

  const selectedDonation = donations.find(d => d.id === selectedId);

  return (
    <div className="w-full h-full absolute top-0 left-0 z-0">
      <MapContainer
        center={[19.0178, 72.8478]}
        zoom={14}
        scrollWheelZoom={false} // Better for mobile experience
        style={{ height: '100%', width: '100%' }}
        zoomControl={false} // We can add custom controls if needed
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          className="silver-map-tiles"
        />

        {/* Map Controller for programmatic movements */}
        <MapController 
          selectedLat={selectedDonation?.lat ?? null} 
          selectedLng={selectedDonation?.lng ?? null} 
        />

        {donations.map((donation) => (
          <Marker
            key={donation.id}
            position={[donation.lat, donation.lng]}
            icon={emeraldIcon}
            eventHandlers={{
              click: () => {
                onSelectMarker(donation.id);
              },
            }}
          />
        ))}
      </MapContainer>
    </div>
  );
};

export default VolunteerMap;

import React, { useState, useEffect, useRef } from 'react';
import { motion, PanInfo, useAnimation, useDragControls } from 'framer-motion';
import { MapPin, Clock, ChevronRight, ArrowLeft, Utensils, Weight, CheckCircle } from 'lucide-react';
import { DonationSheetProps, Donation } from '../types';

const DonationSheet: React.FC<DonationSheetProps> = ({ donations, selectedId, onCloseDetail, onSelectDonation }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const controls = useAnimation();
  const [claimQuantity, setClaimQuantity] = useState<number>(0);
  const [slideProgress, setSlideProgress] = useState(0);
  const slideRef = useRef<HTMLDivElement>(null);

  const selectedDonation = donations.find(d => d.id === selectedId);

  // Reset local state when selection changes
  useEffect(() => {
    if (selectedDonation) {
      setClaimQuantity(Math.floor(selectedDonation.quantity / 2)); // Default to half
      setSlideProgress(0);
      controls.start('expanded');
    } else {
      controls.start('collapsed');
      setIsExpanded(false);
    }
  }, [selectedDonation, controls]);

  const onDragEnd = (event: MouseEvent | TouchEvent | PointerEvent, info: PanInfo) => {
    const threshold = 100;
    if (selectedDonation) {
        // In detail view, drag down to close detail
        if (info.offset.y > threshold) {
            onCloseDetail();
        }
    } else {
        // In list view, toggle expand/collapse
        if (info.offset.y < -threshold) {
            setIsExpanded(true);
            controls.start('expanded');
        } else if (info.offset.y > threshold && isExpanded) {
            setIsExpanded(false);
            controls.start('collapsed');
        } else {
            // Snap back
            controls.start(isExpanded ? 'expanded' : 'collapsed');
        }
    }
  };

  const handleSlideDrag = (event: any, info: PanInfo) => {
    if (!slideRef.current) return;
    const maxDrag = slideRef.current.clientWidth - 56; // width minus button width
    const progress = Math.max(0, Math.min(info.point.x, maxDrag)) / maxDrag;
    // This is a simplified visual representation. Real implementation needs constrained drag.
  };

  const variants = {
    expanded: { y: '15vh' }, // 85% height visible
    collapsed: { y: 'calc(100vh - 220px)' }, // Peeking bottom
  };

  return (
    <motion.div
      initial="collapsed"
      animate={controls}
      variants={variants}
      transition={{ type: 'spring', damping: 25, stiffness: 200 }}
      drag="y"
      dragConstraints={{ top: 0, bottom: 0 }} // Constraints handled by logic
      dragElastic={0.1}
      onDragEnd={onDragEnd}
      className="absolute left-0 right-0 bottom-0 z-50 bg-white rounded-t-3xl shadow-[0_-5px_20px_rgba(0,0,0,0.1)] flex flex-col h-[100vh]"
      style={{ touchAction: 'none' }} // Prevent browser scroll interference
    >
      {/* Handle Bar */}
      <div className="w-full flex justify-center pt-3 pb-1 cursor-grab active:cursor-grabbing">
        <div className="w-12 h-1.5 bg-slate-200 rounded-full" />
      </div>

      {/* Content Container */}
      <div className="flex-1 overflow-hidden relative flex flex-col">

        {/* DETAIL VIEW */}
        {selectedDonation ? (
          <div className="flex flex-col h-full px-6 pb-24 overflow-y-auto no-scrollbar">
            {/* Header */}
            <div className="flex items-center gap-2 mb-4">
              <button 
                onClick={onCloseDetail}
                className="p-2 -ml-2 rounded-full hover:bg-slate-100 transition-colors"
              >
                <ArrowLeft className="w-6 h-6 text-slate-700" />
              </button>
              <h2 className="text-xl font-bold text-slate-900 line-clamp-1">{selectedDonation.hotelName}</h2>
            </div>

            {/* Image */}
            <div className="relative w-full h-48 rounded-2xl overflow-hidden mb-6 shadow-sm">
                <img 
                    src={selectedDonation.imageUrl} 
                    alt={selectedDonation.foodItem} 
                    className="w-full h-full object-cover"
                />
                <div className="absolute top-3 right-3 bg-white/90 backdrop-blur-sm px-3 py-1 rounded-full text-xs font-bold text-emerald-800 shadow-sm">
                    {selectedDonation.distance} away
                </div>
            </div>

            {/* Info */}
            <div className="space-y-4 mb-8">
                <div className="flex justify-between items-start">
                    <div>
                        <h3 className="text-2xl font-bold text-slate-800 mb-1">{selectedDonation.foodItem}</h3>
                        <div className="flex items-center gap-2 text-slate-500 text-sm">
                            <Clock className="w-4 h-4" />
                            <span>Expires in {selectedDonation.expiryTime}</span>
                        </div>
                    </div>
                    <div className="bg-emerald-50 px-3 py-2 rounded-xl flex flex-col items-center">
                        <span className="text-xs text-emerald-600 font-semibold uppercase">Total</span>
                        <span className="text-xl font-bold text-emerald-700">{selectedDonation.quantity}kg</span>
                    </div>
                </div>

                <div className="flex flex-wrap gap-2">
                    {selectedDonation.tags.map(tag => (
                        <span key={tag} className="px-3 py-1 rounded-full bg-slate-100 text-slate-600 text-xs font-medium border border-slate-200">
                            {tag}
                        </span>
                    ))}
                </div>
            </div>

            {/* Partial Claim Slider */}
            <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 mb-8">
                <div className="flex justify-between items-center mb-4">
                    <label className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                        <Weight className="w-4 h-4" />
                        Quantity to Rescue
                    </label>
                    <span className="text-lg font-bold text-emerald-700">{claimQuantity} kg</span>
                </div>
                <input 
                    type="range" 
                    min={1} 
                    max={selectedDonation.quantity} 
                    value={claimQuantity}
                    onChange={(e) => setClaimQuantity(Number(e.target.value))}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-600"
                />
                <div className="flex justify-between mt-2 text-xs text-slate-400">
                    <span>1kg</span>
                    <span>{selectedDonation.quantity}kg (All)</span>
                </div>
            </div>

            {/* Slide to Claim Button */}
            <div className="mt-auto">
                <div 
                    ref={slideRef}
                    className="relative h-14 bg-slate-900 rounded-full overflow-hidden flex items-center shadow-xl shadow-emerald-900/20"
                >
                    <div className="absolute inset-0 flex items-center justify-center text-white font-semibold tracking-wide pointer-events-none z-10">
                        Slide to Confirm Rescue
                    </div>

                    {/* The Draggable Handle */}
                    <motion.div
                        drag="x"
                        dragConstraints={slideRef}
                        dragElastic={0}
                        dragMomentum={false}
                        onDragEnd={(e, info) => {
                            if (slideRef.current && info.point.x > slideRef.current.clientWidth * 0.6) {
                                // Trigger success action
                                alert(`Successfully rescued ${claimQuantity}kg from ${selectedDonation.hotelName}!`);
                                onCloseDetail();
                            }
                        }}
                        className="w-12 h-12 bg-emerald-500 rounded-full absolute left-1 flex items-center justify-center cursor-grab active:cursor-grabbing z-20 shadow-md"
                        whileTap={{ scale: 1.1 }}
                    >
                        <ChevronRight className="text-white w-6 h-6" />
                    </motion.div>
                </div>
            </div>
          </div>
        ) : (
          /* LIST VIEW */
          <div className="flex flex-col h-full">
            <div className="px-6 mb-2">
                <h2 className="text-lg font-bold text-slate-900">Nearby Donations</h2>
                <p className="text-sm text-slate-500">{donations.length} places with food available</p>
            </div>

            {/* Scrollable List Area */}
            <div className={`flex-1 overflow-y-auto ${!isExpanded ? 'overflow-hidden' : ''}`}>
                <div className={`p-6 pt-2 grid gap-4 ${!isExpanded ? 'flex flex-row overflow-x-auto snap-x no-scrollbar pb-8' : 'flex-col'}`}>
                    {donations.map((donation) => (
                        <div 
                            key={donation.id}
                            onClick={() => onSelectDonation(donation.id)}
                            className={`
                                bg-white border border-slate-100 rounded-2xl p-3 shadow-sm flex-shrink-0 cursor-pointer hover:border-emerald-500/50 transition-all
                                ${!isExpanded ? 'w-[280px] snap-center' : 'w-full flex items-center gap-4'}
                            `}
                        >
                            <div className={`${!isExpanded ? 'w-full h-32 mb-3' : 'w-24 h-24'} relative rounded-xl overflow-hidden bg-slate-100 flex-shrink-0`}>
                                <img src={donation.imageUrl} className="w-full h-full object-cover" alt="" />
                                {!isExpanded && (
                                     <div className="absolute top-2 right-2 bg-white/90 px-2 py-0.5 rounded-md text-[10px] font-bold text-slate-700">
                                     {donation.distance}
                                 </div>
                                )}
                            </div>

                            <div className="flex-1 min-w-0">
                                <div className="flex justify-between items-start">
                                    <h3 className="font-bold text-slate-800 truncate">{donation.hotelName}</h3>
                                    {isExpanded && <span className="text-xs font-bold text-slate-500">{donation.distance}</span>}
                                </div>
                                <p className="text-sm text-slate-500 truncate mb-2">{donation.foodItem}</p>

                                <div className="flex items-center gap-3">
                                    <div className="flex items-center gap-1 text-xs font-medium text-emerald-700 bg-emerald-50 px-2 py-1 rounded-md">
                                        <Weight className="w-3 h-3" />
                                        {donation.quantity}kg
                                    </div>
                                    <div className="flex items-center gap-1 text-xs text-amber-600 bg-amber-50 px-2 py-1 rounded-md">
                                        <Clock className="w-3 h-3" />
                                        {donation.expiryTime} left
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
          </div>
        )}
      </div>
    </motion.div>
  );
};

export default DonationSheet;

import React, { useState } from 'react';
import { User, Menu, Search, Bell } from 'lucide-react';
