export default App;

import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, useMap } from 'react-leaflet';
import L from 'leaflet';
import { VolunteerMapProps } from '../types';

// Use a high-quality SVG pin for sharper visuals on mobile
const createCustomIcon = (isSelected: boolean) => new L.Icon({
  iconUrl: isSelected 
    ? 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png' // Highlight color
    : 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-green.png', // Default
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowSize: [41, 41]
});

const MapController: React.FC<{ selectedLat: number | null; selectedLng: number | null }> = ({ selectedLat, selectedLng }) => {
  const map = useMap();

  useEffect(() => {
    if (selectedLat !== null && selectedLng !== null) {
      // Offset the center slightly to account for the bottom sheet covering the bottom half
      const targetPoint = map.project([selectedLat, selectedLng], 15);
      targetPoint.y = targetPoint.y + 100; // Shift map center down so marker appears higher up (visible area)
      const targetLatLng = map.unproject(targetPoint, 15);

      map.flyTo(targetLatLng, 15, {
        animate: true,
        duration: 1.2,
        easeLinearity: 0.25
      });
    }
  }, [selectedLat, selectedLng, map]);

  return null;
};

const VolunteerMap: React.FC<VolunteerMapProps> = ({ donations, selectedId, onSelectMarker }) => {
  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  if (!isMounted) return null;

  const selectedDonation = donations.find(d => d.id === selectedId);

  return (
    <div className="w-full h-full absolute top-0 left-0 z-0">
      <MapContainer
        center={[19.0178, 72.8478]}
        zoom={14}
        zoomControl={false}
        scrollWheelZoom={true}
        attributionControl={false} // Cleaner look
        className="w-full h-full outline-none"
      >
        <TileLayer
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png" // Cleaner base map than OSM default
          className="silver-map-tiles"
        />

        <MapController 
          selectedLat={selectedDonation?.lat ?? null} 
          selectedLng={selectedDonation?.lng ?? null} 
        />

        {donations.map((donation) => (
          <Marker
            key={donation.id}
            position={[donation.lat, donation.lng]}
            icon={createCustomIcon(selectedId === donation.id)}
            eventHandlers={{
              click: () => {
                onSelectMarker(donation.id);
              },
            }}
          />
        ))}
      </MapContainer>

      {/* Decorative gradient overlay at top for better text readability of floating UI */}
      <div className="absolute top-0 left-0 right-0 h-32 bg-gradient-to-b from-white/60 to-transparent pointer-events-none z-[5]" />
    </div>
  );
};

export default VolunteerMap;

import React, { useState, useEffect, useRef } from 'react';
import { motion, PanInfo, useAnimation, useMotionValue, useTransform } from 'framer-motion';
import { Clock, ChevronRight, ArrowLeft, Weight, MapPin, X } from 'lucide-react';
import { DonationSheetProps } from '../types';

const SHEET_MARGIN = 20; // Margin from top when fully expanded

const DonationSheet: React.FC<DonationSheetProps> = ({ donations, selectedId, onCloseDetail, onSelectDonation }) => {
  const [viewState, setViewState] = useState<'collapsed' | 'expanded' | 'detail'>('collapsed');
  const controls = useAnimation();

  // Slider State
  const [claimQuantity, setClaimQuantity] = useState<number>(0);
  const [isConfirmed, setIsConfirmed] = useState(false);

  // Slider Motion
  const slideX = useMotionValue(0);
  const slideRef = useRef<HTMLDivElement>(null);
  const sliderWidth = useMotionValue(0);

  const selectedDonation = donations.find(d => d.id === selectedId);

  // Sync state with props
  useEffect(() => {
    if (selectedDonation) {
      setViewState('detail');
      setClaimQuantity(Math.floor(selectedDonation.quantity / 2));
      setIsConfirmed(false);
      slideX.set(0);
    } else {
      if (viewState === 'detail') setViewState('collapsed'); // Go back to collapsed if closing detail
    }
  }, [selectedDonation]);

  // Handle Sheet Animation based on State
  useEffect(() => {
    const screenHeight = window.innerHeight;

    // Calculate Y positions
    const collapsedY = screenHeight - 240; // Shows ~240px at bottom
    const expandedY = SHEET_MARGIN + 80;   // Near top
    const detailY = SHEET_MARGIN + 40;     // Slightly higher for details

    if (viewState === 'collapsed') {
      controls.start({ y: collapsedY });
    } else if (viewState === 'expanded') {
      controls.start({ y: expandedY });
    } else if (viewState === 'detail') {
      controls.start({ y: detailY });
    }
  }, [viewState, controls]);

  const onDragEnd = (event: any, info: PanInfo) => {
    const threshold = 50;
    const { offset, velocity } = info;

    if (viewState === 'detail') {
      // If dragging down significantly in detail view, close it
      if (offset.y > 150) {
        onCloseDetail();
      } else {
        // Snap back to detail position
        setViewState('detail'); // trigger effect
      }
      return;
    }

    // List Logic
    if (offset.y < -threshold || velocity.y < -500) {
      setViewState('expanded');
    } else if (offset.y > threshold || velocity.y > 500) {
      setViewState('collapsed');
    }
  };

  // Slider Logic
  useEffect(() => {
     if (slideRef.current) {
         sliderWidth.set(slideRef.current.offsetWidth - 56); // 56 is button width
     }
  }, [slideRef, viewState]);

  const handleSliderDragEnd = () => {
    const currentX = slideX.get();
    const max = sliderWidth.get();

    if (currentX > max * 0.7) {
        // Snap to end and confirm
        slideX.set(max);
        setIsConfirmed(true);
        // Simulate API call
        setTimeout(() => {
            alert("Rescue Confirmed! Thank you.");
            onCloseDetail();
        }, 800);
    } else {
        // Snap back
        slideX.set(0);
    }
  };

  // Dynamic Background style for the slider track based on drag
  const slideBgOpacity = useTransform(slideX, [0, 200], [0.1, 1]);
  const slideTextOpacity = useTransform(slideX, [0, 150], [1, 0]);

  return (
    <motion.div
      initial={{ y: window.innerHeight - 200 }}
      animate={controls}
      transition={{ type: 'spring', damping: 28, stiffness: 300 }}
      drag="y"
      dragConstraints={{ top: 0, bottom: window.innerHeight }}
      dragElastic={0.05}
      onDragEnd={onDragEnd}
      className="absolute left-0 right-0 top-0 bottom-0 z-50 bg-white rounded-t-[2.5rem] shadow-[0_-10px_40px_rgba(0,0,0,0.15)] flex flex-col overflow-hidden"
      style={{ touchAction: 'none' }} // Critical for smooth drag
    >
      {/* Visual Handle */}
      <div className="w-full flex justify-center pt-4 pb-2 cursor-grab active:cursor-grabbing shrink-0 z-10 bg-white">
        <div className="w-12 h-1.5 bg-slate-200 rounded-full" />
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden flex flex-col relative h-full">

        {/* === DETAIL VIEW === */}
        {selectedDonation && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="flex flex-col h-full px-6 pb-24 overflow-y-auto no-scrollbar"
          >
            {/* Header */}
            <div className="flex items-center justify-between mb-4 sticky top-0 bg-white z-10 py-2">
              <button 
