import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, useMap } from 'react-leaflet';
import L from 'leaflet';
import { VolunteerMapProps } from '../types';

// Use a high-quality SVG pin for sharper visuals on mobile
const createCustomIcon = (isSelected: boolean) => new L.Icon({
  iconUrl: isSelected 
    ? 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png' // Highlight color
    : 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-green.png', // Default
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowSize: [41, 41]
});

const MapController: React.FC<{ selectedLat: number | null; selectedLng: number | null }> = ({ selectedLat, selectedLng }) => {
  const map = useMap();

  useEffect(() => {
    if (selectedLat !== null && selectedLng !== null) {
      const markerBounds = L.latLngBounds([[selectedLat, selectedLng]]);

      // Use fitBounds with padding to center the marker in the visible area above the bottom sheet
      // paddingBottomRight: [x, y] - Adds padding to the bottom/right of the map viewport
      // Adjust padding based on typical bottom sheet height (e.g., ~350px - 400px)
      map.fitBounds(markerBounds, {
        paddingTopLeft: [0, 100],     // Space for top search bar/header
        paddingBottomRight: [0, 400], // Space for bottom sheet
        maxZoom: 15,
        animate: true,
        duration: 1.2
      });
    }
  }, [selectedLat, selectedLng, map]);

  return null;
};

const VolunteerMap: React.FC<VolunteerMapProps> = ({ donations, selectedId, onSelectMarker }) => {
  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  if (!isMounted) return null;

  const selectedDonation = donations.find(d => d.id === selectedId);

  return (
    <div className="w-full h-full absolute top-0 left-0 z-0">
      <MapContainer
        center={[19.0178, 72.8478]}
        zoom={14}
        zoomControl={false}
        scrollWheelZoom={true}
        attributionControl={false} // Cleaner look
        className="w-full h-full outline-none"
      >
        <TileLayer
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png" // Cleaner base map than OSM default
          className="silver-map-tiles"
        />

        <MapController 
          selectedLat={selectedDonation?.lat ?? null} 
          selectedLng={selectedDonation?.lng ?? null} 
        />

        {donations.map((donation) => (
          <Marker
            key={donation.id}
            position={[donation.lat, donation.lng]}
            icon={createCustomIcon(selectedId === donation.id)}
            eventHandlers={{
              click: () => {
                onSelectMarker(donation.id);
              },
            }}
          />
        ))}
      </MapContainer>

      {/* Decorative gradient overlay at top for better text readability of floating UI */}
      <div className="absolute top-0 left-0 right-0 h-32 bg-gradient-to-b from-white/60 to-transparent pointer-events-none z-[5]" />
    </div>
  );
};

export default VolunteerMap;

