  // Note: Using standard SVGs here as strings for the divIcon
  const iconSvg = isVeg 
    ? `<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#059669" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M11 20A7 7 0 0 1 9.8 6.1C15.5 5 17 4.48 19 2c1 2 2 4.18 2 8 0 5.5-4.77 10-10 10Z"/><path d="M2 21c0-3 1.85-5.36 5.08-6C9.5 14.52 12 13 13 12"/></svg>`
    : `<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#ea580c" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="m21.558 2.85-5.923 5.923a1.445 1.445 0 0 1-2.043 0L7.96 3.14a1.443 1.443 0 0 0-2.043 0l-3.329 3.329a1.443 1.443 0 0 0 0 2.043L8.22 14.15a1.445 1.445 0 0 1 0 2.043l-5.923 5.923m3.882-3.882-3.883 3.883"/><path d="m14.15 8.22 5.633 5.633a1.445 1.445 0 0 1 0 2.043l-3.328 3.329a1.443 1.443 0 0 0 0 2.043l3.329-3.329a1.443 1.443 0 0 0 2.043 0l3.329 3.328a1.445 1.445 0 0 1 0 2.043L19.5 17.67"/></svg>`;

  const size = isSelected ? 'w-12 h-12' : 'w-10 h-10';
  const ringColor = isSelected ? 'ring-4 ring-emerald-500/30' : 'ring-1 ring-slate-200';
  const shadow = isSelected ? 'shadow-2xl' : 'shadow-md';
  const zIndex = isSelected ? 1000 : 100;

  return L.divIcon({
    className: 'custom-map-marker',
    html: `
      <div class="${size} ${ringColor} ${shadow} bg-white rounded-full flex items-center justify-center transition-all duration-300 transform" style="position: relative; z-index: ${zIndex};">
        ${iconSvg}
        ${isSelected ? '<div class="absolute -bottom-1 w-2 h-2 bg-emerald-600 rotate-45"></div>' : ''}
      </div>
    `,
    iconSize: isSelected ? [48, 48] : [40, 40],
    iconAnchor: isSelected ? [24, 52] : [20, 20], // Adjusted anchor for "pin" feel when selected
    popupAnchor: [0, -40]
  });
};

const MapController: React.FC<{ selectedLat: number | null; selectedLng: number | null }> = ({ selectedLat, selectedLng }) => {
  const map = useMap();

  useEffect(() => {
    if (selectedLat !== null && selectedLng !== null) {
      const markerBounds = L.latLngBounds([[selectedLat, selectedLng]]);

      // Increased Top Padding to account for the new Search + Filter bar (~180px)
      map.fitBounds(markerBounds, {
        paddingTopLeft: [0, 180],     
        paddingBottomRight: [0, 400], 
        maxZoom: 16,
        animate: true,
        duration: 1.2
      });
    }
  }, [selectedLat, selectedLng, map]);

  return null;
};

const VolunteerMap: React.FC<VolunteerMapProps> = ({ donations, selectedId, onSelectMarker }) => {
  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  if (!isMounted) return (
    <div className="w-full h-full bg-slate-100 flex flex-col items-center justify-center">
        <div className="w-10 h-10 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
        <span className="text-slate-400 font-medium">Loading Map...</span>
    </div>
  );

  const selectedDonation = donations.find(d => d.id === selectedId);

  return (
    <div className="w-full h-full absolute top-0 left-0 z-0">
      <MapContainer
        center={USER_LOCATION}
        zoom={14}
        zoomControl={false}
        scrollWheelZoom={true}
        attributionControl={false}
        className="w-full h-full outline-none"
      >
        <TileLayer
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png" 
          className="silver-map-tiles"
        />

        {/* User Location Marker (Simple Blue Dot) */}
        <Marker 
          position={USER_LOCATION} 
          icon={L.divIcon({
            className: 'user-loc-marker',
            html: '<div class="w-4 h-4 bg-blue-500 border-2 border-white rounded-full shadow-lg relative"><div class="absolute inset-0 bg-blue-500 rounded-full animate-ping opacity-75"></div></div>',
            iconSize: [16, 16]
          })}
        />

        <MapController 
          selectedLat={selectedDonation?.lat ?? null} 
          selectedLng={selectedDonation?.lng ?? null} 
        />

        {/* Route Line */}
        {selectedDonation && (
          <Polyline 
            positions={[USER_LOCATION, [selectedDonation.lat, selectedDonation.lng]]}
            pathOptions={{ color: '#059669', dashArray: '10, 10', weight: 3, opacity: 0.6 }}
          />
        )}

        {donations.map((donation) => (
          <Marker
            key={donation.id}
            position={[donation.lat, donation.lng]}
            icon={createCustomMarker(donation, selectedId === donation.id)}
            eventHandlers={{
              click: () => {
                onSelectMarker(donation.id);
              },
            }}
          />
        ))}
      </MapContainer>

      {/* Top Gradient for text readability */}
      <div className="absolute top-0 left-0 right-0 h-40 bg-gradient-to-b from-white/80 via-white/40 to-transparent pointer-events-none z-[5]" />
    </div>
  );
};

export default VolunteerMap;

import React, { useState, useEffect, useRef } from 'react';
import { motion, PanInfo, useAnimation, useMotionValue, useTransform } from 'framer-motion';
import { Clock, ChevronRight, ArrowLeft, Weight, MapPin, SearchX, Timer } from 'lucide-react';
import { DonationSheetProps } from '../types';

const SHEET_MARGIN = 20;

const DonationSheet: React.FC<DonationSheetProps> = ({ donations, selectedId, onCloseDetail, onSelectDonation }) => {
  const [viewState, setViewState] = useState<'collapsed' | 'expanded' | 'detail'>('collapsed');
  const [loading, setLoading] = useState(true);
  const controls = useAnimation();

  // Slider State
  const [claimQuantity, setClaimQuantity] = useState<number>(0);
  const [isConfirmed, setIsConfirmed] = useState(false);
  const slideX = useMotionValue(0);
  const slideRef = useRef<HTMLDivElement>(null);
  const sliderWidth = useMotionValue(0);

  const selectedDonation = donations.find(d => d.id === selectedId);

  // Simulate initial data loading
  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 1500);
    return () => clearTimeout(timer);
  }, []);

  // Sync state with props
  useEffect(() => {
    if (selectedDonation) {
      setViewState('detail');
      setClaimQuantity(Math.floor(selectedDonation.quantity / 2));
      setIsConfirmed(false);
      slideX.set(0);
    } else {
      if (viewState === 'detail') setViewState('collapsed'); 
    }
  }, [selectedDonation]);

  // Handle Sheet Animation
  useEffect(() => {
    const screenHeight = window.innerHeight;
    // Lower the collapsed state slightly to show more map
    const collapsedY = screenHeight - 260; 
    const expandedY = SHEET_MARGIN + 120; // Adjusted for taller top bar
    const detailY = SHEET_MARGIN + 60;

    if (viewState === 'collapsed') controls.start({ y: collapsedY });
    else if (viewState === 'expanded') controls.start({ y: expandedY });
    else if (viewState === 'detail') controls.start({ y: detailY });
  }, [viewState, controls]);

  const onDragEnd = (event: any, info: PanInfo) => {
    const threshold = 50;
    const { offset, velocity } = info;

    if (viewState === 'detail') {
      if (offset.y > 150) onCloseDetail();
      else setViewState('detail'); 
      return;
    }

    if (offset.y < -threshold || velocity.y < -500) setViewState('expanded');
    else if (offset.y > threshold || velocity.y > 500) setViewState('collapsed');
  };

  // Slider Logic
  useEffect(() => {
     if (slideRef.current) sliderWidth.set(slideRef.current.offsetWidth - 56);
  }, [slideRef, viewState]);

  const handleSliderDragEnd = () => {
    const currentX = slideX.get();
    const max = sliderWidth.get();

    if (currentX > max * 0.7) {
        slideX.set(max);
        setIsConfirmed(true);
        setTimeout(() => {
            alert("Rescue Confirmed! Thank you.");
            onCloseDetail();
        }, 800);
    } else {
        slideX.set(0);
    }
  };

  const slideBgOpacity = useTransform(slideX, [0, 200], [0.1, 1]);
  const slideTextOpacity = useTransform(slideX, [0, 150], [1, 0]);

  // --- Sub-components for Cleaner Code ---

  const SkeletonCard = () => (
    <div className="w-[280px] bg-white border border-slate-100 rounded-2xl p-3 shrink-0">
       <div className="w-full h-32 bg-slate-200 rounded-xl animate-pulse mb-3" />
       <div className="h-4 bg-slate-200 rounded w-3/4 animate-pulse mb-2" />
       <div className="h-3 bg-slate-200 rounded w-1/2 animate-pulse" />
    </div>
  );

  const EmptyState = () => (
    <div className="flex flex-col items-center justify-center h-48 w-full text-center p-6 opacity-70">
        <div className="bg-slate-100 p-4 rounded-full mb-3">
            <SearchX className="w-8 h-8 text-slate-400" />
        </div>
        <h3 className="font-bold text-slate-700">No donations found</h3>
        <p className="text-xs text-slate-500">Try adjusting your filters or search a different area.</p>
    </div>
  );

  return (
    <motion.div
      initial={{ y: window.innerHeight - 200 }}
      animate={controls}
      transition={{ type: 'spring', damping: 28, stiffness: 300 }}
      drag="y"
      dragConstraints={{ top: 0, bottom: window.innerHeight }}
      dragElastic={0.05}
      onDragEnd={onDragEnd}
      className="absolute left-0 right-0 top-0 bottom-0 z-30 bg-white rounded-t-[2.5rem] shadow-[0_-10px_40px_rgba(0,0,0,0.15)] flex flex-col overflow-hidden"
      style={{ touchAction: 'none' }} 
    >
      <div className="w-full flex justify-center pt-4 pb-2 cursor-grab active:cursor-grabbing shrink-0 z-10 bg-white">
        <div className="w-12 h-1.5 bg-slate-200 rounded-full" />
      </div>

      <div className="flex-1 overflow-hidden flex flex-col relative h-full">

        {/* === DETAIL VIEW === */}
        {selectedDonation && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="flex flex-col h-full px-6 pb-24 overflow-y-auto no-scrollbar"
          >
            {/* Header */}
            <div className="flex items-center justify-between mb-4 sticky top-0 bg-white z-10 py-2">
              <button onClick={onCloseDetail} className="p-2 -ml-2 rounded-full hover:bg-slate-100 transition-colors group">
                <ArrowLeft className="w-6 h-6 text-slate-700 group-hover:-translate-x-1 transition-transform" />
              </button>
              <div className="bg-emerald-100 text-emerald-800 px-3 py-1 rounded-full text-xs font-bold tracking-wide">
                ACTIVE RESCUE
              </div>
            </div>

            <h2 className="text-2xl font-bold text-slate-900 leading-tight mb-1">{selectedDonation.hotelName}</h2>
            <p className="text-slate-500 text-sm mb-5 flex items-center gap-1">
                <MapPin className="w-3.5 h-3.5" /> 
                {selectedDonation.distance} away
            </p>

            <div className="relative w-full aspect-video rounded-3xl overflow-hidden mb-6 shadow-md">
                <img src={selectedDonation.imageUrl} alt={selectedDonation.foodItem} className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                <div className="absolute bottom-4 left-4 text-white">
                    <h3 className="text-lg font-bold">{selectedDonation.foodItem}</h3>
                    <div className="flex gap-2 mt-1">
                         {selectedDonation.tags.map(tag => (
                            <span key={tag} className="px-2 py-0.5 rounded-md bg-white/20 backdrop-blur-sm text-xs border border-white/30">
                                {tag}
                            </span>
                        ))}
                    </div>
                </div>
            </div>

            <div className="bg-slate-50 border border-slate-100 shadow-inner rounded-2xl p-5 mb-6">
                <div className="flex justify-between items-center mb-4">
                     <div className="flex items-center gap-3">
                        <div className="p-2.5 bg-white rounded-xl shadow-sm text-emerald-600">
                             <Weight className="w-5 h-5" />
                        </div>
                        <div>
                            <div className="text-xs text-slate-500 font-semibold uppercase">Total Weight</div>
                            <div className="text-lg font-bold text-slate-900">{selectedDonation.quantity} kg</div>
                        </div>
                     </div>
                     <div className="h-8 w-px bg-slate-200" />
                     <div className="flex items-center gap-3">
                        <div className="p-2.5 bg-white rounded-xl shadow-sm text-amber-600">
                             <Clock className="w-5 h-5" />
                        </div>
                        <div>
                            <div className="text-xs text-slate-500 font-semibold uppercase">Expires In</div>
                            <div className="text-lg font-bold text-slate-900">{selectedDonation.expiryTime}</div>
                        </div>
                     </div>
                </div>
            </div>

            <div className="mb-8">
                <div className="flex justify-between items-end mb-3">
                    <label className="text-sm font-bold text-slate-700">Rescuing Amount</label>
                    <span className="text-2xl font-bold text-emerald-600">{claimQuantity} <span className="text-sm text-slate-400 font-normal">kg</span></span>
                </div>
                <input 
                    type="range" min={1} max={selectedDonation.quantity} value={claimQuantity}
                    onChange={(e) => setClaimQuantity(Number(e.target.value))}
                    className="w-full h-3 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-emerald-600 hover:accent-emerald-500 transition-all"
                />
            </div>

            <div className="mt-auto pb-4">
                <div ref={slideRef} className="relative h-16 bg-slate-900 rounded-full overflow-hidden flex items-center justify-between p-1.5 shadow-xl shadow-emerald-900/10">
                    <motion.div style={{ opacity: slideTextOpacity }} className="absolute inset-0 flex items-center justify-center text-white/90 font-semibold tracking-wide pointer-events-none">
                        Slide to Rescue
                    </motion.div>

                    <motion.div 
                        style={{ opacity: isConfirmed ? 1 : 0 }}
                        className="absolute inset-0 bg-emerald-600 flex items-center justify-center text-white font-bold tracking-wide z-10 transition-opacity duration-300"
                    >
                        Rescued!
                    </motion.div>

                    <motion.div
                        drag="x"
                        dragConstraints={{ left: 0, right: sliderWidth.get() || 200 }}
                        dragElastic={0}
                        dragMomentum={false}
                        onDragEnd={handleSliderDragEnd}
                        style={{ x: slideX }}
                        className="w-14 h-13 bg-white rounded-full flex items-center justify-center shadow-md relative z-20 cursor-grab active:cursor-grabbing"
                    >
                        {isConfirmed ? <CheckCircle className="text-emerald-600 w-6 h-6" /> : <ChevronRight className="text-slate-900 w-6 h-6" />}
                    </motion.div>
                </div>
            </div>
          </motion.div>
        )}

        {/* === LIST VIEW === */}
        {!selectedDonation && (
          <motion.div className="flex flex-col h-full" animate={{ opacity: 1 }} initial={{ opacity: 1 }}>
            <div className="px-6 pb-2 pt-0 shrink-0 flex justify-between items-end">
                <div>
                    <h2 className="text-xl font-bold text-slate-900">Nearby Donations</h2>
                    <p className="text-sm text-slate-500">
                        {loading ? 'Searching nearby...' : `${donations.length} opportunities found`}
                    </p>
                </div>
                {!loading && <button onClick={() => setViewState(viewState === 'collapsed' ? 'expanded' : 'collapsed')} className="text-xs font-bold text-emerald-600 mb-1">
                    {viewState === 'collapsed' ? 'View All' : 'Show Map'}
                </button>}
            </div>

            <div className={`flex-1 ${viewState === 'expanded' ? 'overflow-y-auto' : 'overflow-hidden'}`}>
                <div className={`p-6 pt-2 gap-4 transition-all duration-300 ${viewState === 'collapsed' ? 'flex flex-row overflow-x-auto snap-x no-scrollbar' : 'flex flex-col pb-32'}`}>

                    {loading ? (
                        <>
                           <SkeletonCard />
                           <SkeletonCard />
                           <SkeletonCard />
                        </>
                    ) : donations.length === 0 ? (
                        <EmptyState />
                    ) : (
                        donations.map((donation) => (
                            <div 
                                key={donation.id}
                                onClick={() => onSelectDonation(donation.id)}
                                className={`
                                    relative bg-white border border-slate-100 rounded-2xl p-0 shadow-sm hover:shadow-lg transition-all cursor-pointer overflow-hidden group
                                    ${viewState === 'collapsed' ? 'w-[280px] snap-center shrink-0 flex flex-col' : 'w-full flex h-32'}
                                `}
                            >
                                {/* Rich Card Image with Timer */}
                                <div className={`relative bg-slate-100 ${viewState === 'collapsed' ? 'h-40 w-full' : 'w-32 h-full'}`}>
                                    <img src={donation.imageUrl} className="w-full h-full object-cover" alt="" />
                                    {/* Gradient Overlay */}
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-60" />

                                    {/* Live Timer Badge */}
                                    <div className="absolute top-2 right-2 bg-red-500/90 backdrop-blur-sm text-white text-[10px] font-bold px-2 py-1 rounded-full flex items-center gap-1 shadow-sm">
                                        <Timer className="w-3 h-3" />
                                        {donation.expiryTime}
                                    </div>
                                </div>

                                <div className="flex-1 p-3 flex flex-col justify-between">
                                    <div>
                                        <h3 className="font-bold text-slate-800 truncate text-base mb-1">{donation.hotelName}</h3>
                                        <p className="text-xs text-slate-500 line-clamp-1 mb-2">{donation.foodItem}</p>
                                    </div>

                                    {/* Info Row */}
                                    <div className="flex items-center justify-between mt-auto">
                                        <div className="flex gap-3 text-slate-600">
                                            <div className="flex items-center gap-1 text-xs font-semibold">
                                                <MapPin className="w-3 h-3 text-emerald-600" /> {donation.distance}
                                            </div>
                                            <div className="flex items-center gap-1 text-xs font-semibold">
                                                <Weight className="w-3 h-3 text-emerald-600" /> {donation.quantity}kg
                                            </div>
                                        </div>

                                        {viewState !== 'collapsed' && (
                                            <button className="bg-slate-900 text-white text-xs font-bold px-3 py-1.5 rounded-lg shadow-md transform active:scale-95 transition-all">
                                                View
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>
          </motion.div>
        )}
      </div>

      {!selectedDonation && viewState === 'expanded' && (
        <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-white to-transparent pointer-events-none" />
      )}
    </motion.div>
  );
};

function CheckCircle({ className }: { className?: string }) {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className={className}>
            <path d="M20 6 9 17l-5-5" />
        </svg>
    )
}

export default DonationSheet;
